CREATE TABLE recipe_cuisine (
                                id                      BIGINT          PRIMARY KEY,
                                value                   VARCHAR(100)    NOT NULL UNIQUE,
                                country_localized_key   VARCHAR(255)    NOT NULL,
                                label_localized_key     VARCHAR(255)    NOT NULL,
                                flag                    VARCHAR(10)     NULL
);

-- Indexes
CREATE INDEX idx_recipe_cuisine_value ON recipe_cuisine (value);

